import { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import API from '../api/axios';

export default function AdminDashboard() {
  const [stats, setStats] = useState({ users: [], appointments: [], services: [] });
  const [tab, setTab] = useState('overview');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      API.get('/admin/users'),
      API.get('/admin/appointments'),
      API.get('/services')
    ]).then(([u, a, s]) => {
      setStats({ users: u.data, appointments: a.data, services: s.data });
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const deleteUser = async (id) => {
    if (!window.confirm('Delete this user?')) return;
    await API.delete(`/admin/users/${id}`);
    setStats(prev => ({ ...prev, users: prev.users.filter(u => u._id !== id) }));
    toast.success('User deleted');
  };

  const updateApptStatus = async (id, status) => {
    await API.put(`/appointments/${id}/status`, { status });
    setStats(prev => ({ ...prev, appointments: prev.appointments.map(a => a._id === id ? { ...a, status } : a) }));
    toast.success('Status updated');
  };

  const overview = [
    { label: 'Total Users', value: stats.users.length, icon: '👥', color: '#6366f1' },
    { label: 'Providers', value: stats.users.filter(u => u.role === 'provider').length, icon: '🏪', color: '#10b981' },
    { label: 'Appointments', value: stats.appointments.length, icon: '📅', color: '#a855f7' },
    { label: 'Services', value: stats.services.length, icon: '⭐', color: '#f59e0b' },
  ];

  const TABS = ['overview', 'users', 'appointments', 'services'];

  return (
    <div style={{ minHeight: '100vh', background: '#0f0f1a', padding: '100px 40px 40px' }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>

        <div style={{ marginBottom: '40px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '8px' }}>
            <div style={{ width: 48, height: 48, borderRadius: '12px', background: 'rgba(255, 27, 27, 0.96)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '24px' }}>🛡️</div>
            <div>
              <h1 style={{ fontSize: '32px', fontWeight: 800, }}>Admin Dashboard</h1>
              <p style={{ color: 'rgb(227, 15, 15)', fontSize: '14px' }}>Full system control panel</p>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '32px', background: 'rgba(255,255,255,0.05)', padding: '6px', borderRadius: '12px', width: 'fit-content' }}>
          {TABS.map(t => (
            <button key={t} onClick={() => setTab(t)} style={{
              padding: '8px 20px', borderRadius: '8px', border: 'none', cursor: 'pointer',
              fontWeight: 600, fontSize: '13px', transition: 'all 0.3s', textTransform: 'capitalize',
              background: tab === t ? 'linear-gradient(135deg, #6366f1, #a855f7)' : 'transparent',
              color: tab === t ? '#fff' : 'rgba(255,255,255,0.5)'
            }}>{t}</button>
          ))}
        </div>

        {/* Overview */}
        {tab === 'overview' && (
          <div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px', marginBottom: '32px' }}>
              {overview.map((o, i) => (
                <div key={i} className="glass" style={{ padding: '24px', display: 'flex', alignItems: 'center', gap: '16px' }}>
                  <div style={{ width: 52, height: 52, borderRadius: '14px', background: `${o.color}22`, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '26px', border: `1px solid ${o.color}44` }}>{o.icon}</div>
                  <div>
                    <div style={{ fontSize: '32px', fontWeight: 800, color: o.color }}>{o.value}</div>
                    <div style={{ fontSize: '13px', color: 'rgba(241, 20, 20, 0.92)' }}>{o.label}</div>
                  </div>
                </div>
              ))}
            </div>
            <div className="glass" style={{ padding: '24px' }}>
              <h3 style={{ marginBottom: '16px', color: 'rgba(194, 210, 20, 0.83)' }}>Recent Appointments</h3>
              {stats.appointments.slice(0, 5).map(a => (
                <div key={a._id} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid rgba(255,255,255,0.06)', alignItems: 'center' }}>
                  <div>
                    <span style={{ fontWeight: 600 }}>{a.service?.name}</span>
                    <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '13px', marginLeft: '12px' }}>{a.customer?.name} → {a.provider?.name}</span>
                  </div>
                  <span className={`badge badge-${a.status}`}>{a.status}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Users */}
        {tab === 'users' && (
          <div className="glass" style={{ padding: '24px' }}>
            <h3 style={{ marginBottom: '20px' }}>All Users ({stats.users.length})</h3>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
                    {['Name', 'Email', 'Role', 'Joined', 'Action'].map(h => (
                      <th key={h} style={{ padding: '12px 16px', textAlign: 'left', color: 'rgba(255,255,255,0.5)', fontSize: '13px', fontWeight: 600 }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {stats.users.map(u => (
                    <tr key={u._id} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                      <td style={{ padding: '14px 16px', fontWeight: 600 }}>{u.name}</td>
                      <td style={{ padding: '14px 16px', color: 'rgba(255,255,255,0.6)', fontSize: '13px' }}>{u.email}</td>
                      <td style={{ padding: '14px 16px' }}>
                        <span style={{
                          padding: '3px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: 600,
                          background: u.role === 'admin' ? 'rgba(239,68,68,0.15)' : u.role === 'provider' ? 'rgba(16,185,129,0.15)' : 'rgba(99,102,241,0.15)',
                          color: u.role === 'admin' ? '#ef4444' : u.role === 'provider' ? '#10b981' : '#6366f1'
                        }}>{u.role}</span>
                      </td>
                      <td style={{ padding: '14px 16px', color: 'rgba(255,255,255,0.4)', fontSize: '13px' }}>{new Date(u.createdAt).toLocaleDateString()}</td>
                      <td style={{ padding: '14px 16px' }}>
                        {u.role !== 'admin' && (
                          <button onClick={() => deleteUser(u._id)} style={{ background: 'rgba(239,68,68,0.15)', color: '#ef4444', border: '1px solid rgba(239,68,68,0.3)', padding: '5px 12px', borderRadius: '6px', cursor: 'pointer', fontSize: '12px' }}>Delete</button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Appointments */}
        {tab === 'appointments' && (
          <div className="glass" style={{ padding: '24px' }}>
            <h3 style={{ marginBottom: '20px' }}>All Appointments ({stats.appointments.length})</h3>
            {stats.appointments.map(a => (
              <div key={a._id} style={{ padding: '16px', marginBottom: '12px', background: 'rgba(255,255,255,0.03)', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.07)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
                <div>
                  <span style={{ fontWeight: 700 }}>{a.service?.name}</span>
                  <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '13px', display: 'block' }}>{a.customer?.name} → {a.provider?.name} | {a.date} {a.timeSlot}</span>
                </div>
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                  <span className={`badge badge-${a.status}`}>{a.status}</span>
                  <select onChange={e => updateApptStatus(a._id, e.target.value)} value={a.status}
                    style={{ background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.15)', color: '#fff', padding: '5px 10px', borderRadius: '6px', fontSize: '12px', cursor: 'pointer' }}>
                    {['pending', 'confirmed', 'cancelled', 'completed'].map(s => <option key={s} value={s}>{s}</option>)}
                  </select>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Services */}
        {tab === 'services' && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' }}>
            {stats.services.map(s => (
              <div key={s._id} className="glass" style={{ padding: '20px' }}>
                <h4 style={{ marginBottom: '8px' }}>{s.name}</h4>
                <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '13px', marginBottom: '12px' }}>{s.description}</p>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '13px', color: 'rgba(255,255,255,0.6)' }}>
                  <span>⏱ {s.duration} mins</span>
                  <span style={{ color: '#a855f7', fontWeight: 700 }}>₹{s.price}</span>
                </div>
                <div style={{ fontSize: '12px', color: 'rgba(255,255,255,0.4)', marginTop: '8px' }}>👤 {s.provider?.name}</div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
